import { useQuery } from "@tanstack/react-query";
import { workScheduleService } from "@/api/workScheduleService";
import { queryKeys } from '@/lib/queryKeys';
import type { WorkScheduleMonthSummary } from "@/types/dto";

export function useMyWorkScheduleMonths() {
  return useQuery<WorkScheduleMonthSummary[]>({
    queryKey: queryKeys.workSchedule.monthsMy(),
    queryFn: () => workScheduleService.getMyMonths(),
    staleTime: 1000 * 60,
  });
}

export function useUserWorkScheduleMonths(userId: string, options?: { enabled?: boolean }) {
  return useQuery<WorkScheduleMonthSummary[]>({
    queryKey: queryKeys.workSchedule.monthsUser(userId),
    queryFn: () => workScheduleService.getUserMonths(userId),
    enabled: (options?.enabled ?? true) && !!userId,
    staleTime: 1000 * 60,
  });
}
