import { useMemo, type ReactNode } from "react";
import { format } from "date-fns";
import { HarmonyTable, type HarmonyColumn } from "@/components/ui/harmony-table";
import { Badge } from "@/shadcn/components/ui/badge";
import type { WorkScheduleMonthSummary } from "@/types/dto";
import { SCHEDULE_STATUS } from "../constants";
import { WorkScheduleStatus } from "@/types/enums";

interface WorkScheduleMonthListProps {
  months: WorkScheduleMonthSummary[];
  loading: boolean;
  onRowClick: (month: WorkScheduleMonthSummary) => void;
  /** Shown in the table title when viewing another user's schedule. */
  userName?: string;
  /** Injected into the table toolbar right slot (e.g. "Plan for…" buttons). */
  toolbarRight?: ReactNode;
}

export function WorkScheduleMonthList({
  months,
  loading,
  onRowClick,
  userName,
  toolbarRight,
}: WorkScheduleMonthListProps) {
  const columns = useMemo<HarmonyColumn<WorkScheduleMonthSummary>[]>(() => [
    {
      key: "month",
      header: "Month",
      width: 160,
      renderCell: ({ row }) => (
        <span className="font-medium">
          {format(new Date(row.year, row.month - 1, 1), "MMMM yyyy")}
        </span>
      ),
    },
    {
      key: "status",
      header: "Status",
      width: 130,
      renderCell: ({ row }) => {
        const statusKey = row.status as WorkScheduleStatus;
        const cfg = SCHEDULE_STATUS[statusKey];
        if (!cfg) return <span>{row.status}</span>;
        const Icon = cfg.icon;
        return (
          <Badge variant="outline" className={`${cfg.color} gap-1.5 font-semibold text-xs`}>
            <Icon size={11} />
            {cfg.label}
          </Badge>
        );
      },
    },
    {
      key: "days",
      header: "Days Filed",
      width: 110,
      renderCell: ({ row }) => (
        <span className="tabular-nums text-sm">
          <span className={row.filledDaysCount === row.workingDaysCount ? "text-emerald-600 font-semibold" : ""}>
            {row.filledDaysCount}
          </span>
          <span className="text-muted-foreground"> / {row.workingDaysCount}</span>
        </span>
      ),
    },
    {
      key: "reviewNotes",
      header: "Review Notes",
      renderCell: ({ row }) =>
        row.reviewNotes ? (
          <span className="text-xs text-muted-foreground truncate" title={row.reviewNotes}>
            {row.reviewNotes.length > 60 ? `${row.reviewNotes.slice(0, 60)}…` : row.reviewNotes}
          </span>
        ) : (
          <span className="text-xs text-muted-foreground/40">—</span>
        ),
    },
  ], []);

  return (
    <HarmonyTable
      rows={months}
      columns={columns}
      rowKeyGetter={(row) => row.id}
      loading={loading}
      title={userName ? `${userName}'s Work Schedules` : "My Work Schedules"}
      description="Monthly schedule records — click a row to view the calendar"
      emptyMessage="No schedule records found."
      onCellClick={(row) => onRowClick(row)}
      rowClass={() => "cursor-pointer"}
      toolbarRight={toolbarRight}
    />
  );
}
